const fs = require('fs');
const zlib = require('zlib');
const path = require('path');

console.log('');
console.log('  브링엔지니어링 경영관리 시스템 설치 중...');
console.log('');

const files = [
  { name: 'server.js', data: "" },
  { name: 'start.bat', data: "" },
  { name: '브링엔지니어링_경영관리.html', data: "" }
];

files.forEach(f => {
  const buf = zlib.gunzipSync(Buffer.from(f.data, 'base64'));
  fs.writeFileSync(f.name, buf);
  console.log('  + ' + f.name + ' (' + buf.length + ' bytes)');
});

if (!fs.existsSync('data')) fs.mkdirSync('data');
if (!fs.existsSync(path.join('data','documents'))) fs.mkdirSync(path.join('data','documents'), {recursive:true});
console.log('  + data/ 폴더');
console.log('');
console.log('  설치 완료!');
console.log('  실행: node server.js');
console.log('  접속: http://localhost:3000');
console.log('');
